import { useState } from 'react';
import { motion } from 'framer-motion';
import { Calculator, IndianRupee, Percent, Calendar, TrendingUp, TrendingDown } from 'lucide-react';

const EMICalculatorPage = () => {
  const [propertyPrice, setPropertyPrice] = useState(5000000);
  const [downPaymentPercent, setDownPaymentPercent] = useState(20);
  const [interestRate, setInterestRate] = useState(8.5);
  const [loanTenure, setLoanTenure] = useState(20);
  const [emi, setEmi] = useState(0);
  const [totalPayment, setTotalPayment] = useState(0);
  const [totalInterest, setTotalInterest] = useState(0);

  const calculateEMI = () => {
    const downPaymentAmount = (propertyPrice * downPaymentPercent) / 100;
    const loanAmount = propertyPrice - downPaymentAmount;
    const monthlyRate = interestRate / 100 / 12;
    const months = loanTenure * 12;
    
    if (loanAmount > 0 && monthlyRate > 0) {
      const emiValue = loanAmount * monthlyRate * Math.pow(1 + monthlyRate, months) / (Math.pow(1 + monthlyRate, months) - 1);
      const totalPayable = emiValue * months;
      const totalInterestPayable = totalPayable - loanAmount;
      
      setEmi(Math.round(emiValue));
      setTotalPayment(Math.round(totalPayable));
      setTotalInterest(Math.round(totalInterestPayable));
    }
  };

  const formatCurrency = (amount) => {
    if (amount >= 10000000) return `₹${(amount / 10000000).toFixed(2)} Cr`;
    if (amount >= 100000) return `₹${(amount / 100000).toFixed(1)} Lakhs`;
    return `₹${amount.toLocaleString('en-IN')}`;
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="pt-32 pb-16 bg-gradient-to-br from-gray-50 to-white min-h-screen"
    >
      <div className="container-custom">
        <div className="text-center mb-12">
          <h1 className="text-4xl md:text-5xl font-bold text-[#0a192f] mb-4">EMI Calculator</h1>
          <p className="text-gray-600 text-lg">Plan your home loan with our easy EMI calculator</p>
        </div>

        <div className="grid lg:grid-cols-2 gap-12">
          {/* Input Section */}
          <div className="bg-white rounded-2xl shadow-xl p-8">
            <div className="space-y-6">
              <div>
                <label className="flex items-center gap-2 text-gray-700 font-semibold mb-3">
                  <IndianRupee size={20} className="text-[#c6a43b]" />
                  Property Price
                </label>
                <input
                  type="range"
                  min="1000000"
                  max="50000000"
                  step="500000"
                  value={propertyPrice}
                  onChange={(e) => {
                    setPropertyPrice(Number(e.target.value));
                    setTimeout(calculateEMI, 0);
                  }}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-[#c6a43b]"
                />
                <div className="flex justify-between mt-2">
                  <span className="text-sm text-gray-500">₹10 Lakhs</span>
                  <span className="text-[#c6a43b] font-bold">{formatCurrency(propertyPrice)}</span>
                  <span className="text-sm text-gray-500">₹5 Crore</span>
                </div>
              </div>

              <div>
                <label className="flex items-center gap-2 text-gray-700 font-semibold mb-3">
                  <Percent size={20} className="text-[#c6a43b]" />
                  Down Payment ({downPaymentPercent}%)
                </label>
                <input
                  type="range"
                  min="10"
                  max="50"
                  step="5"
                  value={downPaymentPercent}
                  onChange={(e) => {
                    setDownPaymentPercent(Number(e.target.value));
                    setTimeout(calculateEMI, 0);
                  }}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-[#c6a43b]"
                />
                <div className="flex justify-between mt-2">
                  <span className="text-sm text-gray-500">10%</span>
                  <span className="text-[#c6a43b] font-bold">{formatCurrency((propertyPrice * downPaymentPercent) / 100)}</span>
                  <span className="text-sm text-gray-500">50%</span>
                </div>
              </div>

              <div>
                <label className="flex items-center gap-2 text-gray-700 font-semibold mb-3">
                  <TrendingUp size={20} className="text-[#c6a43b]" />
                  Interest Rate (% p.a.)
                </label>
                <input
                  type="range"
                  min="6"
                  max="15"
                  step="0.1"
                  value={interestRate}
                  onChange={(e) => {
                    setInterestRate(Number(e.target.value));
                    setTimeout(calculateEMI, 0);
                  }}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-[#c6a43b]"
                />
                <div className="flex justify-between mt-2">
                  <span className="text-sm text-gray-500">6%</span>
                  <span className="text-[#c6a43b] font-bold">{interestRate}%</span>
                  <span className="text-sm text-gray-500">15%</span>
                </div>
              </div>

              <div>
                <label className="flex items-center gap-2 text-gray-700 font-semibold mb-3">
                  <Calendar size={20} className="text-[#c6a43b]" />
                  Loan Tenure (Years)
                </label>
                <input
                  type="range"
                  min="5"
                  max="30"
                  step="5"
                  value={loanTenure}
                  onChange={(e) => {
                    setLoanTenure(Number(e.target.value));
                    setTimeout(calculateEMI, 0);
                  }}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-[#c6a43b]"
                />
                <div className="flex justify-between mt-2">
                  <span className="text-sm text-gray-500">5 years</span>
                  <span className="text-[#c6a43b] font-bold">{loanTenure} years</span>
                  <span className="text-sm text-gray-500">30 years</span>
                </div>
              </div>

              <button
                onClick={calculateEMI}
                className="w-full bg-[#c6a43b] text-[#0a192f] py-3 rounded-lg font-bold hover:bg-opacity-90 transition"
              >
                Calculate EMI
              </button>
            </div>
          </div>

          {/* Results Section */}
          <div className="bg-gradient-to-br from-[#0a192f] to-[#1e2a3a] rounded-2xl shadow-xl p-8 text-white">
            <h3 className="text-2xl font-bold mb-6 text-center">Your Loan Summary</h3>
            
            <div className="space-y-6">
              <div className="text-center">
                <p className="text-gray-300 mb-2">Monthly EMI</p>
                <p className="text-5xl font-bold text-[#c6a43b]">{formatCurrency(emi)}</p>
              </div>

              <div className="grid grid-cols-2 gap-6 pt-6 border-t border-white/20">
                <div>
                  <p className="text-gray-300 text-sm">Loan Amount</p>
                  <p className="text-2xl font-bold">{formatCurrency(propertyPrice - (propertyPrice * downPaymentPercent) / 100)}</p>
                </div>
                <div>
                  <p className="text-gray-300 text-sm">Total Interest</p>
                  <p className="text-2xl font-bold text-orange-400">{formatCurrency(totalInterest)}</p>
                </div>
                <div className="col-span-2">
                  <p className="text-gray-300 text-sm">Total Payment</p>
                  <p className="text-2xl font-bold">{formatCurrency(totalPayment)}</p>
                </div>
              </div>

              <div className="bg-white/10 rounded-lg p-4 mt-4">
                <p className="text-sm text-gray-300 text-center">
                  *EMI calculations are estimates. Actual rates may vary by lender.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default EMICalculatorPage;
